namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private readonly List<Notification> _notifications = new();
    private int _nextId;

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            new Notification(++_nextId, "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-30)),
            new Notification(++_nextId, "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-15)),
            new Notification(++_nextId, "New feature: dark mode is now available.", DateTime.UtcNow.AddMinutes(-5)),
        });
    }

    /// <summary>Returns all notifications.</summary>
    public List<Notification> GetAll() => _notifications.OrderByDescending(n => n.Timestamp).ToList();

    /// <summary>Returns only notifications newer than the given timestamp.</summary>
    public List<Notification> GetSince(DateTime since) =>
        _notifications.Where(n => n.Timestamp > since).OrderByDescending(n => n.Timestamp).ToList();

    /// <summary>Simulates an incoming notification (called by background activity or tests).</summary>
    public Notification Add(string message)
    {
        var notification = new Notification(Interlocked.Increment(ref _nextId), message, DateTime.UtcNow);
        _notifications.Add(notification);
        return notification;
    }
}

@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h2>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h2>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in _notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    // Runs during both prerender AND interactive init.
    // On prerender: loads initial data for server-rendered HTML.
    // On interactive init: the same data is already serialized via persistent component state,
    // so we only need to kick off the polling loop.
    protected override void OnInitialized()
    {
        _notifications = NotificationSvc.GetAll();
    }

    // Called exactly once after the component is interactive in the browser.
    // This is the safe place to start the polling loop — it will NOT run during prerender.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            var latest = _notifications.Count > 0 ? _notifications.Max(n => n.Timestamp) : DateTime.MinValue;
            var newer = NotificationSvc.GetSince(latest);

            if (newer.Count > 0)
            {
                // Prepend new items (already sorted newest-first).
                _notifications.InsertRange(0, newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

