namespace NotificationsApp.Services;

/// <summary>
/// Background service that adds a fake notification every ~8 seconds
/// so there is something for the polling loop to pick up.
/// </summary>
public class FakeNotificationProducer : BackgroundService
{
    private static readonly string[] Messages =
    {
        "Server CPU usage is back to normal.",
        "Deployment to staging succeeded.",
        "A new user signed up.",
        "Disk space warning on node-3.",
        "Scheduled backup completed.",
        "SSL certificate renewed.",
    };

    private readonly NotificationService _svc;

    public FakeNotificationProducer(NotificationService svc) => _svc = svc;

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        var rng = new Random();
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(8), stoppingToken);
            _svc.Add(Messages[rng.Next(Messages.Length)]);
        }
    }
}

